   177	        internal async Task UpdateGroupingOrder(Column<T> column, bool added)
   178	        {
   179	            // if added then add to the end if no _groupByOrderState.Value
   180	            if (added)
   181	            {
   182	                var groupedColumns = RenderedColumns.Where(x => x.GroupingState.Value && x != column);
   183	                var newOrder = groupedColumns.Any() ? groupedColumns.Max(x => x._groupByOrderState.Value) + 1 : 0;
   184	                await column._groupByOrderState.SetValueAsync(newOrder);
   185	            }
   186	            // if removed then reset _groupByOrderState.Value
   187	            else
   188	            {
   189	                await column._groupByOrderState.SetValueAsync(default);
   190	            }
   191	            // expand all but last grouped column when changed
   192	            await GroupExpansion();
   193	        }
   194	
   195	        private async Task GroupExpansion()
   196	        {
   197	            var groupedColumns = RenderedColumns.Where(x => x.GroupingState.Value).OrderBy(x => x._groupByOrderState.Value).SkipLast(1);
   198	            foreach (var col in groupedColumns.OrderBy(x => x._groupByOrderState.Value))
   199	            {
   200	                await col._groupExpandedState.SetValueAsync(true);
   201	            }
   202	        }
